import{_ as d,o as a,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"算电协同 · 投资逻辑框架","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"算电协同/投资逻辑.md","filePath":"算电协同/投资逻辑.md","lastUpdated":1781535932000}'),r={name:"算电协同/投资逻辑.md"};function o(l,t,e,i,h,p){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="算电协同-·-投资逻辑框架" tabindex="-1">算电协同 · 投资逻辑框架 <a class="header-anchor" href="#算电协同-·-投资逻辑框架" aria-label="Permalink to &quot;算电协同 · 投资逻辑框架&quot;">​</a></h1><p><strong>视角：</strong> PE/VC 一级股权投资 <strong>当前阶段：</strong> 早期布局期（2025-2027 窗口期）</p><hr><h2 id="一、三句话判断" tabindex="-1">一、三句话判断 <a class="header-anchor" href="#一、三句话判断" aria-label="Permalink to &quot;一、三句话判断&quot;">​</a></h2><blockquote><p><strong>第一句：&quot;双 80&quot;是硬约束不是口号——绿电占比 80% + PUE 1.25，决定了谁的节能体系好谁才能获批新建。</strong> 能效从&quot;可选项&quot;变为&quot;准入门槛&quot;。</p></blockquote><blockquote><p><strong>第二句：看得见的钱在设备（液冷/储能），看不见的钱在平台（调度/交易/能效优化）。</strong> 一级市场应该赌平台型机会，设备是二级市场的。</p></blockquote><blockquote><p><strong>第三句：2026年5月广东数据中心 VPP 现货交易首单证伪了&quot;数据中心不能参与电力市场&quot;的假设。</strong> 最大机会在帮数据中心省电和赚钱的轻资产平台——AI 制冷优化 SaaS 和 VPP 聚合平台。</p></blockquote><hr><h2 id="二、投资机会矩阵" tabindex="-1">二、投资机会矩阵 <a class="header-anchor" href="#二、投资机会矩阵" aria-label="Permalink to &quot;二、投资机会矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>子赛道</th><th>投资时机</th><th>壁垒类型</th><th>资本效率</th><th>退出路径</th><th>PE/VC推荐</th></tr></thead><tbody><tr><td><strong>AI制冷优化SaaS（新）</strong></td><td>✅ 窗口期</td><td>算法+数据</td><td><strong>极高</strong></td><td>独立上市/被收购</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td><strong>数据中心需求响应平台</strong></td><td>✅ 现在</td><td>客户关系+运营</td><td>中等</td><td>被收购（能源公司）</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td><strong>AI电力交易平台</strong></td><td>✅ 窗口期</td><td>算法+数据</td><td>高</td><td>独立上市/被收购</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td><strong>VPP聚合数据中心（新）</strong></td><td>✅ 首单验证</td><td>客户资源+平台</td><td>中等</td><td>被收购</td><td>⭐⭐⭐⭐</td></tr><tr><td><strong>算力调度平台</strong></td><td>✅ 窗口期</td><td>网络效应</td><td>高</td><td>被收购</td><td>⭐⭐⭐⭐</td></tr><tr><td><strong>液冷散热（冷板式）</strong></td><td>✅ 现在</td><td>客户验证</td><td>低-中</td><td>IPO</td><td>⭐⭐⭐</td></tr><tr><td><strong>液冷散热（浸没式）</strong></td><td>📝 关注</td><td>技术突破</td><td>低</td><td>被收购</td><td>⭐⭐⭐</td></tr><tr><td><strong>低功耗推理芯片</strong></td><td>✅ 窗口期</td><td>芯片设计+生态</td><td>低（烧钱）</td><td>IPO</td><td>⭐⭐⭐</td></tr><tr><td><strong>存量数据中心改造（新）</strong></td><td>✅ 政策驱动</td><td>方案+安全验证</td><td>中</td><td>项目退出</td><td>⭐⭐⭐</td></tr><tr><td><strong>源网荷储一体化项目</strong></td><td>📝 谨慎</td><td>资金+资源</td><td>低（重资产）</td><td>项目退出</td><td>⭐⭐</td></tr></tbody></table><blockquote><p><strong>2026-06-12 更新说明：</strong></p><ul><li>⬆ 新增 AI 制冷优化 SaaS 为 P0（全球空白市场，海外 Phaidra 已验证模式）</li><li>⬆ VPP 聚合数据中心升级热度（2026年5月国内首单落地）</li><li>⬆ 浸没式液冷从 ⭐⭐ 升至 ⭐⭐⭐（NVIDIA Rubin 全液冷路线确认）</li><li>➕ 新增存量数据中心改造（政策明确要求推进）</li><li>详见 <code>节能用能体系深度分析.md</code></li></ul></blockquote><hr><h2 id="三、投资策略建议" tabindex="-1">三、投资策略建议 <a class="header-anchor" href="#三、投资策略建议" aria-label="Permalink to &quot;三、投资策略建议&quot;">​</a></h2><h3 id="_3-1-优先布局-p0" tabindex="-1">3.1 优先布局（P0） <a class="header-anchor" href="#_3-1-优先布局-p0" aria-label="Permalink to &quot;3.1 优先布局（P0）&quot;">​</a></h3><ol><li><p><strong>AI制冷优化SaaS</strong> ⭐⭐⭐⭐⭐ — 全球空白，轻资产高壁垒</p><ul><li><strong>投资逻辑</strong>：海外 Phaidra 已为 Google 降低 30% 制冷能耗，国内对标空白</li><li>数据中心制冷占能耗 30-40%，AI 优化可节省 10-30%</li><li>毛利率 60-80%，SaaS 模式可复制</li><li><strong>关键验证</strong>：算法精度、跨平台兼容性（能否适配多种 GPU/制冷方案）</li><li><strong>国内现状</strong>：暂无专注 AI 制冷优化的独立公司</li></ul></li><li><p><strong>AI电力交易平台</strong> — 壁垒最高、资本效率最高</p><ul><li>投资逻辑：电力现货市场扩容→交易频次增加→AI报价策略需求爆发</li><li>关键验证：是否有真实交易数据、策略夏普比率</li><li>代表：瓦特智能、清大科越</li></ul></li><li><p><strong>算力调度平台</strong> — 网络效应，先发优势明显</p><ul><li>投资逻辑：跨区域/跨云调度需求随算力增长指数上升</li><li>关键验证：签约算力规模、客户留存率</li><li>代表：算力互联、星链算力</li></ul></li></ol><h3 id="_3-2-重点跟踪-p1" tabindex="-1">3.2 重点跟踪（P1） <a class="header-anchor" href="#_3-2-重点跟踪-p1" aria-label="Permalink to &quot;3.2 重点跟踪（P1）&quot;">​</a></h3><ol start="4"><li><strong>数据中心需求响应平台</strong> — 政策驱动确定性强（2026年5月国内首单验证）</li><li><strong>VPP聚合数据中心平台</strong> — AI+能源交叉，增长快</li></ol><h3 id="_3-3-关注等待-p2" tabindex="-1">3.3 关注等待（P2） <a class="header-anchor" href="#_3-3-关注等待-p2" aria-label="Permalink to &quot;3.3 关注等待（P2）&quot;">​</a></h3><ol start="5"><li><strong>浸没式液冷</strong> — 技术路线未定，等标杆案例</li><li><strong>源网荷储一体化项目</strong> — 重资产，适合产业资本而非财务投资</li></ol><hr><h2 id="四、估值参考" tabindex="-1">四、估值参考 <a class="header-anchor" href="#四、估值参考" aria-label="Permalink to &quot;四、估值参考&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>收入规模</th><th>估值范围</th><th>说明</th></tr></thead><tbody><tr><td>天使/种子</td><td>0</td><td>1000-3000万</td><td>团队+概念验证</td></tr><tr><td>Pre-A/A轮</td><td>0-500万</td><td>5000万-2亿</td><td>产品落地+1-2个标杆客户</td></tr><tr><td>B轮</td><td>500-3000万</td><td>3-10亿</td><td>规模复制+ARR&gt;500万</td></tr><tr><td>C轮+</td><td>3000万+</td><td>10亿+</td><td>准备上市/被并购</td></tr></tbody></table><hr><h2 id="五、关键验证问题" tabindex="-1">五、关键验证问题 <a class="header-anchor" href="#五、关键验证问题" aria-label="Permalink to &quot;五、关键验证问题&quot;">​</a></h2><p>做 DD 时必问：</p><ol><li><strong>收入质量</strong>：客户是试点项目还是持续付费？续约率？</li><li><strong>竞争壁垒</strong>：为什么电网/数据中心不自己做？</li><li><strong>数据飞轮</strong>：使用越多，模型越准吗？</li><li><strong>政策依赖</strong>：如果电改进度放缓，商业模式还成立吗？</li><li><strong>团队背景</strong>：有没有既懂电力又懂AI的复合人才？</li></ol><hr><h2 id="六、退出路径" tabindex="-1">六、退出路径 <a class="header-anchor" href="#六、退出路径" aria-label="Permalink to &quot;六、退出路径&quot;">​</a></h2><table tabindex="0"><thead><tr><th>退出方式</th><th>概率</th><th>典型收购方</th><th>估值倍数</th></tr></thead><tbody><tr><td>IPO（科创/创业板）</td><td>低（早期）</td><td>—</td><td>8-15x PS</td></tr><tr><td>被能源公司收购</td><td>中高</td><td>国电南瑞/中电科/华能</td><td>3-8x PS</td></tr><tr><td>被科技公司收购</td><td>中</td><td>华为/阿里云/腾讯云</td><td>5-10x PS</td></tr><tr><td>被数据中心运营商收购</td><td>中</td><td>万国数据/秦淮数据</td><td>3-6x PS</td></tr></tbody></table><hr><hr><h2 id="七、投资方角色定位-商业模式回答" tabindex="-1">七、投资方角色定位（商业模式回答） <a class="header-anchor" href="#七、投资方角色定位-商业模式回答" aria-label="Permalink to &quot;七、投资方角色定位（商业模式回答）&quot;">​</a></h2><blockquote><p><strong>回答待深化问题 P0 #1&quot;谁最终付费？&quot;—— 终端付费方始终是算力用户，投资方作为总集成商切入。</strong></p></blockquote><h3 id="_7-1-价值链条" tabindex="-1">7.1 价值链条 <a class="header-anchor" href="#_7-1-价值链条" aria-label="Permalink to &quot;7.1 价值链条&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>绿电供给方                      算力用户（最终付费）</span></span>
<span class="line"><span>    ↑                                ↑</span></span>
<span class="line"><span>    |         ┌──────────────┐        |</span></span>
<span class="line"><span>    └─────────┤  总集成商    ├────────┘</span></span>
<span class="line"><span>              │  （我们）    │</span></span>
<span class="line"><span>    ┌─────────┤             │◄───────┐</span></span>
<span class="line"><span>    ↑         └──────────────┘        ↑</span></span>
<span class="line"><span> 绿电交易方                       设备厂商</span></span>
<span class="line"><span>（代理分成）                     （代理分成）</span></span></code></pre></div><h3 id="_7-2-四种切入角色-从轻到重" tabindex="-1">7.2 四种切入角色（从轻到重） <a class="header-anchor" href="#_7-2-四种切入角色-从轻到重" aria-label="Permalink to &quot;7.2 四种切入角色（从轻到重）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>模式</th><th>资本投入</th><th>利润空间</th><th>核心能力要求</th></tr></thead><tbody><tr><td><strong>A. 纯出资方</strong></td><td>投钱给算力出租方/总集方，吃资本回报</td><td>高</td><td>中等（IRR 8-12%）</td><td>募资能力、项目判断</td></tr><tr><td><strong>B. 渠道代理方</strong></td><td>联合设备方（液冷/储能/GPU）拓展订单，按成交额抽成</td><td>低</td><td>中高（佣金3-8%）</td><td>客户资源、行业关系</td></tr><tr><td><strong>C. 绿电撮合方</strong></td><td>连接绿电项目与算力需求方，吃绿电交易/PPA撮合佣金</td><td>低</td><td>中（佣金2-5%）</td><td>绿电资源、电力交易理解</td></tr><tr><td><strong>D. 总集成方</strong></td><td>整合节能技术+绿电+设备+运营，给算力出租方交钥匙</td><td>中</td><td>高（净利15-25%）</td><td>技术理解、供应链、交付能力</td></tr></tbody></table><h3 id="_7-3-策略建议-分层组合" tabindex="-1">7.3 策略建议：分层组合 <a class="header-anchor" href="#_7-3-策略建议-分层组合" aria-label="Permalink to &quot;7.3 策略建议：分层组合&quot;">​</a></h3><p>不单选一种角色，而是<strong>根据项目情况灵活组合</strong>：</p><ul><li><strong>核心竞争力 → 做D（总集成商）</strong>：当团队/资源到位，吃最大利润</li><li><strong>资源变现 → 做B+C</strong>：有客户关系做渠道，有绿电资源做撮合</li><li><strong>能力不足 → 做A</strong>：纯出资，借助别人的专业能力</li><li><strong>理想路径</strong>：A（建立信任）→ B+C（积累资源）→ D（能力成熟后收割）</li></ul><h3 id="_7-4-落地示例" tabindex="-1">7.4 落地示例 <a class="header-anchor" href="#_7-4-落地示例" aria-label="Permalink to &quot;7.4 落地示例&quot;">​</a></h3><p>假设一个算力出租方需要建千P智算中心：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>算力出租方 → 需要：设备采购 + 液冷方案 + 绿电供应 + 运营服务</span></span>
<span class="line"><span>                    ↓</span></span>
<span class="line"><span>我们作为总集成商 → 整合：</span></span>
<span class="line"><span>  ├── 设备采购（联合英维克/高澜 → 赚代理佣金）</span></span>
<span class="line"><span>  ├── 绿电供应（对接风光电站 → 赚绿电撮合佣金）</span></span>
<span class="line"><span>  ├── 节能方案（引入AI制冷SaaS → 赚技术整合费）</span></span>
<span class="line"><span>  └── 自己出资一部分（赚资本回报）</span></span></code></pre></div><hr><p><em>更新：2026-06-12 | 新增§七 投资方角色定位（基于合伙人框架）</em></p>`,45)])])}const u=d(r,[["render",o]]);export{c as __pageData,u as default};
